#include <stdio.h>
#include <math.h>

int main() {
  double x = 9.0;
  printf("sqrt(%.1f) = %.2f\n", x, sqrt(x));
  printf("pow(2, 10) = %.0f\n", pow(2, 10));
  printf("ceil(3.2) = %.1f\n", ceil(3.2));
  printf("floor(3.8) = %.1f\n", floor(3.8));
  printf("fabs(-5.5) = %.1f\n", fabs(-5.5));
  printf("log(e) = %.4f\n", log(exp(1.0)));
  return 0;
}
